-- Verify
SELECT
  p.name AS parent,
  COUNT(c.id) AS subcategory_count
FROM public.categories p
LEFT JOIN public.categories c ON c.parent_id = p.id
WHERE p.id::text LIKE 'e100%'
GROUP BY p.name, p.sort_order
ORDER BY p.sort_order;
